import { NextRequest, NextResponse } from 'next/server';
import { connectToDatabase } from '@/lib/mongodb';

export async function GET() {
  try {
    const { db } = await connectToDatabase();
    const students = await db.collection('students').find().toArray();
    return NextResponse.json(students);
  } catch (error) {
    return NextResponse.json({ error: String(error) }, { status: 500 });
  }
}

export async function POST(req: NextRequest) {
  try {
    const data = await req.json();
    const { db } = await connectToDatabase();

    const last = await db.collection('students').find().sort({ id: -1 }).limit(1).toArray();
    const lastNum = last.length > 0 ? parseInt(last[0].id.replace('s', ''), 10) : 0;
    const newId = 's' + String(lastNum + 1).padStart(3, '0');

    const student = { id: newId, ...data, pendaftaran_status: 'menunggu_verifikasi' };
    await db.collection('students').insertOne(student);
    return NextResponse.json(student);
  } catch (error) {
    return NextResponse.json({ error: String(error) }, { status: 500 });
  }
}
